// ---------------------------------------------------------------------------
// Connection-state transitions. Each writes connection_state plus the derived
// legacy status/health_status (ADR-041 keeps the legacy columns in sync), and
// the relevant timestamp/reason/generation fields.
// ---------------------------------------------------------------------------
// pending_enrollment/degraded/disconnected → connected. Refreshes liveness and
// clears the disconnected_at/reason set by a prior down transition. The legacy
// status='active'/health_status='healthy' mirror the new connection_state.
func (q *Queries) MarkSiteConnected(ctx context.Context, arg MarkSiteConnectedParams) (Site, error) {
	row := q.db.QueryRow(ctx, markSiteConnected, arg.ID, arg.TenantID)
	var i Site
	err := row.Scan(
		&i.ID,
		&i.TenantID,
		&i.Url,
		&i.Name,
		&i.Status,
		&i.WpVersion,
		&i.PhpVersion,
		&i.AgentVersion,
		&i.AgentPublicKey,
		&i.EnrolledAt,
		&i.LastSeenAt,
		&i.HealthStatus,
		&i.ServerInfo,
		&i.Multisite,
		&i.ActiveTheme,
		&i.Components,
		&i.Tags,
		&i.AgeRecipient,
		&i.WpTimezone,
		&i.WpGmtOffset,
		&i.HostProvider,
		&i.HostProviderOrg,
		&i.HostProviderIp,
		&i.HostProviderCheckedAt,
		&i.ConnectionState,
		&i.ConnectionGeneration,
		&i.DisconnectedAt,
		&i.DisconnectedReason,
		&i.ArchivedAt,
		&i.MissedHeartbeats,
		&i.ClientID,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

