const pruneSiteEvents = `-- name: PruneSiteEvents :execrows
DELETE FROM site_events
WHERE created_at < $1
`

// Ring-buffer prune: drop events older than the replay window (cross-tenant,
// app.agent GUC). Bounds table growth.
func (q *Queries) PruneSiteEvents(ctx context.Context, createdAt time.Time) (int64, error) {
	result, err := q.db.Exec(ctx, pruneSiteEvents, createdAt)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

const replaySiteEvents = `-- name: ReplaySiteEvents :many
SELECT event_id, tenant_id, site_id, type, data, created_at FROM site_events
WHERE tenant_id = $1 AND event_id > $2
ORDER BY event_id
LIMIT $3
`

type ReplaySiteEventsParams struct {
	TenantID uuid.UUID `json:"tenant_id"`
	EventID  string    `json:"event_id"`
	Limit    int32     `json:"limit"`
}

// Replays events after a client cursor (?since / Last-Event-ID). ULIDs sort
// lexicographically, so event_id > $2 is monotonic-after.
func (q *Queries) ReplaySiteEvents(ctx context.Context, arg ReplaySiteEventsParams) ([]SiteEvent, error) {
	rows, err := q.db.Query(ctx, replaySiteEvents, arg.TenantID, arg.EventID, arg.Limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []SiteEvent
	for rows.Next() {
		var i SiteEvent
		if err := rows.Scan(
			&i.EventID,
			&i.TenantID,
			&i.SiteID,
			&i.Type,
			&i.Data,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

